SELECT FROM edu_news n LEFT JOIN edu_news_category c ON c.id = n.category_id AND c.deleted = 0 WHERE n.deleted = 0
AND n.title LIKE CONCAT('%', #{title}, '%')
AND n.category_id = #{categoryId}
AND n.status = #{status}
ORDER BY n.publish_time DESC, n.id DESC

SELECT FROM edu_news n LEFT JOIN edu_news_category c ON c.id = n.category_id AND c.deleted = 0 WHERE n.deleted = 0 AND n.status = 1
AND n.category_id = #{categoryId}
ORDER BY n.publish_time DESC, n.id DESC
